sql:
SELECT risk_factor_name 
FROM risk_factors 
WHERE risk_factor_id IN (2, 3);

SELECT location, COUNT(*) AS evaluation_count
FROM performance_evaluations
GROUP BY location;

external_knowledge:
'Particular gender division' refers to 'Specific Gender Group';
'Members' means individuals part of the performance evaluations related to the specified gender group;
'Details of the performance evaluations' implies all the information available in the `performance_evaluations` table for those members.

sql:
SELECT evaluation_name 
FROM evaluations
WHERE evaluation_id = 1;

SELECT COUNT(DISTINCT value) AS total_risk_factors
FROM performance_evaluations,
json_each(risk_factor_ids);

SELECT AVG(average_predicted_probability) AS average_predicted_probability
FROM performance_evaluations
WHERE person_count_with_outcome > 500 AND location = 'USA';
